mapper.sql:
WHERE is_active = 'Y'

    AND data_type = #{p.dataType}


    AND demand_agency_name LIKE CONCAT('%', #{p.demandAgencyName}, '%')


    AND demand_agency_region LIKE CONCAT('%', #{p.demandAgencyRegion}, '%')


    AND vendor_biz_reg_no = #{p.vendorBizRegNo}


    AND item_category_no LIKE CONCAT('%', #{p.itemCategoryNo}, '%')


    AND detail_item_no = #{p.detailItemNo}


    AND is_mas = #{p.isMas}


    AND is_excellent_product = #{p.isExcellentProduct}


    AND contract_date >= CONCAT(#{p.year}, '-01-01')
    AND contract_date <  DATE_ADD(CONCAT(#{p.year}, '-01-01'), INTERVAL 1 YEAR)


    AND contract_date >= CONCAT(#{p.month}, '-01')
    AND contract_date <  DATE_ADD(CONCAT(#{p.month}, '-01'), INTERVAL 1 MONTH)


    AND contract_date >= CONCAT(#{p.rangeStart}, '-01')
    AND contract_date <  DATE_ADD(CONCAT(#{p.rangeEnd}, '-01'), INTERVAL 1 MONTH)


    AND saved = 'Y'

mapper.update:
UPDATE specific_item_flat
SET saved = #{saved}
WHERE contract_no = #{contractNo}

    AND change_seq = #{changeSeq}


    AND item_seq = #{itemSeq}

UPDATE specific_item_grouped
SET saved = #{saved}
WHERE data_type = #{dataType}
  AND group_key = #{groupKey}
  AND vendor_biz_reg_no <=> #{vendorBizRegNo}
